using Financeiro.Application.DTOs; using Financeiro.Application.Interfaces; using Microsoft.AspNetCore.Authorization; using Microsoft.AspNetCore.Mvc;
namespace Financeiro.API.Controllers; [ApiController][Authorize][Route("api/periodos")] public class PeriodosController : ControllerBase { private readonly IPeriodoService _service; public PeriodosController(IPeriodoService service){_service=service;} [HttpGet] public async Task<IActionResult> Get(CancellationToken ct)=>Ok(await _service.GetAllAsync(ct)); [HttpPost] public async Task<IActionResult> Post([FromBody] PeriodoRequestDto request,CancellationToken ct)=>Ok(await _service.CreateAsync(request,ct)); [HttpPut("{id:guid}")] public async Task<IActionResult> Put(Guid id,[FromBody] PeriodoRequestDto request,CancellationToken ct)=>Ok(await _service.UpdateAsync(id,request,ct)); [HttpPatch("{id:guid}")] public async Task<IActionResult> Patch(Guid id,[FromBody] PeriodoRequestDto request,CancellationToken ct)=>Ok(await _service.UpdateAsync(id,request,ct)); [HttpDelete("{id:guid}")] public async Task<IActionResult> Delete(Guid id,CancellationToken ct)=>Ok(await _service.DeleteAsync(id,ct)); [HttpPost("{periodoId:guid}/despesas")] public async Task<IActionResult> PostDespesa(Guid periodoId,[FromBody] DespesaRequestDto request,CancellationToken ct)=>Ok(await _service.AddDespesaAsync(periodoId,request,ct)); [HttpDelete("{periodoId:guid}/despesas/{despesaId:guid}")] public async Task<IActionResult> DeleteDespesa(Guid periodoId,Guid despesaId,CancellationToken ct)=>Ok(await _service.DeleteDespesaAsync(periodoId,despesaId,ct)); }
